/**
 * Category Service Tests
 *
 * Unit tests for CategoryService covering:
 * - Category CRUD operations
 * - Hierarchical category management
 * - Category reordering
 * - Slug validation
 * - Active status toggling
 *
 * @module modules/menu/__tests__/category.service.spec
 */

import { describe, it, expect, beforeEach, vi, type Mock } from 'vitest';

import { CategoryService } from '@/modules/menu/category.service';
import { AppException } from '@/core/exceptions/app.exception';
import type { CategoryRepository, PaginatedResult } from '@/modules/menu/category.repository';
import type { MenuRepository } from '@/modules/menu/menu.repository';
import type { EventService } from '@/core/services/event.service';
import type { Category, CategoryWithRelations, Menu } from '@/modules/menu/menu.types';

// -----------------------------------------------------------------------------
// Mock Factories
// -----------------------------------------------------------------------------

/**
 * Creates a mock CategoryRepository
 */
function createMockCategoryRepository(): {
  findAll: Mock;
  findAllSummaries: Mock;
  findByMenuId: Mock;
  findById: Mock;
  findByIdWithRelations: Mock;
  findByIdOrThrow: Mock;
  findBySlug: Mock;
  slugExists: Mock;
  count: Mock;
  countAll: Mock;
  create: Mock;
  update: Mock;
  reorder: Mock;
  moveToParent: Mock;
  softDelete: Mock;
  restore: Mock;
} {
  return {
    findAll: vi.fn(),
    findAllSummaries: vi.fn(),
    findByMenuId: vi.fn(),
    findById: vi.fn(),
    findByIdWithRelations: vi.fn(),
    findByIdOrThrow: vi.fn(),
    findBySlug: vi.fn(),
    slugExists: vi.fn(),
    count: vi.fn(),
    countAll: vi.fn(),
    create: vi.fn(),
    update: vi.fn(),
    reorder: vi.fn(),
    moveToParent: vi.fn(),
    softDelete: vi.fn(),
    restore: vi.fn(),
  };
}

/**
 * Creates a mock MenuRepository
 */
function createMockMenuRepository(): {
  findByIdOrThrow: Mock;
} {
  return {
    findByIdOrThrow: vi.fn(),
  };
}

/**
 * Creates a mock EventService
 */
function createMockEventService(): {
  emitCustom: Mock;
} {
  return {
    emitCustom: vi.fn(),
  };
}

/**
 * Creates a mock category for testing
 */
function createMockCategory(overrides: Partial<Category> = {}): Category {
  return {
    id: 'cat_123',
    organizationId: 'org_123',
    menuId: 'menu_123',
    parentId: null,
    name: 'Test Category',
    slug: 'test-category',
    description: 'A test category',
    image: null,
    isActive: true,
    sortOrder: 0,
    createdAt: new Date(),
    updatedAt: new Date(),
    deletedAt: null,
    ...overrides,
  };
}

/**
 * Creates a mock category with relations
 */
function createMockCategoryWithRelations(
  overrides: Partial<CategoryWithRelations> = {}
): CategoryWithRelations {
  return {
    ...createMockCategory(),
    parent: null,
    children: [],
    products: [],
    ...overrides,
  };
}

/**
 * Creates a mock menu for testing
 */
function createMockMenu(overrides: Partial<Menu> = {}): Menu {
  return {
    id: 'menu_123',
    organizationId: 'org_123',
    branchId: null,
    themeId: null,
    name: 'Test Menu',
    slug: 'test-menu',
    description: null,
    isPublished: false,
    isDefault: true,
    publishedAt: null,
    settings: {},
    sortOrder: 0,
    createdAt: new Date(),
    updatedAt: new Date(),
    deletedAt: null,
    ...overrides,
  };
}

// -----------------------------------------------------------------------------
// Test Suite
// -----------------------------------------------------------------------------

describe('CategoryService', () => {
  let service: CategoryService;
  let mockCategoryRepository: ReturnType<typeof createMockCategoryRepository>;
  let mockMenuRepository: ReturnType<typeof createMockMenuRepository>;
  let mockEventService: ReturnType<typeof createMockEventService>;

  const orgId = 'org_123';
  const menuId = 'menu_123';

  beforeEach(() => {
    mockCategoryRepository = createMockCategoryRepository();
    mockMenuRepository = createMockMenuRepository();
    mockEventService = createMockEventService();

    service = new CategoryService(
      mockCategoryRepository as unknown as CategoryRepository,
      mockMenuRepository as unknown as MenuRepository,
      mockEventService as unknown as EventService
    );
  });

  // ---------------------------------------------------------------------------
  // Read Operations Tests
  // ---------------------------------------------------------------------------

  describe('list', () => {
    it('should return paginated categories', async () => {
      // Arrange
      const categories = [createMockCategory(), createMockCategory({ id: 'cat_456' })];
      const paginatedResult: PaginatedResult<Category> = {
        data: categories,
        meta: { page: 1, perPage: 50, total: 2, totalPages: 1 },
      };
      mockCategoryRepository.findAll.mockResolvedValue(paginatedResult);

      // Act
      const result = await service.list(orgId, { menuId, page: 1, perPage: 50 });

      // Assert
      expect(result).toEqual(paginatedResult);
      expect(mockCategoryRepository.findAll).toHaveBeenCalledWith(
        orgId,
        expect.objectContaining({ menuId })
      );
    });

    it('should filter by active status', async () => {
      // Arrange
      const paginatedResult: PaginatedResult<Category> = {
        data: [createMockCategory({ isActive: true })],
        meta: { page: 1, perPage: 50, total: 1, totalPages: 1 },
      };
      mockCategoryRepository.findAll.mockResolvedValue(paginatedResult);

      // Act
      await service.list(orgId, { menuId, isActive: true });

      // Assert
      expect(mockCategoryRepository.findAll).toHaveBeenCalledWith(
        orgId,
        expect.objectContaining({ isActive: true })
      );
    });
  });

  describe('listSummaries', () => {
    it('should return category summaries for a menu', async () => {
      // Arrange
      const summaries = [
        {
          id: 'cat_123',
          name: 'Category 1',
          slug: 'category-1',
          menuId,
          parentId: null,
          isActive: true,
          sortOrder: 0,
          productCount: 5,
          childCount: 2,
          createdAt: new Date(),
        },
      ];
      mockMenuRepository.findByIdOrThrow.mockResolvedValue(createMockMenu());
      mockCategoryRepository.findAllSummaries.mockResolvedValue(summaries);

      // Act
      const result = await service.listSummaries(orgId, menuId);

      // Assert
      expect(result).toEqual(summaries);
      expect(mockMenuRepository.findByIdOrThrow).toHaveBeenCalledWith(menuId, orgId);
    });
  });

  describe('getByMenuId', () => {
    it('should return categories for a menu', async () => {
      // Arrange
      const categories = [createMockCategory(), createMockCategory({ id: 'cat_456' })];
      mockMenuRepository.findByIdOrThrow.mockResolvedValue(createMockMenu());
      mockCategoryRepository.findByMenuId.mockResolvedValue(categories);

      // Act
      const result = await service.getByMenuId(orgId, menuId);

      // Assert
      expect(result).toEqual(categories);
      expect(mockMenuRepository.findByIdOrThrow).toHaveBeenCalledWith(menuId, orgId);
    });

    it('should filter by parent ID', async () => {
      // Arrange
      mockMenuRepository.findByIdOrThrow.mockResolvedValue(createMockMenu());
      mockCategoryRepository.findByMenuId.mockResolvedValue([]);

      // Act
      await service.getByMenuId(orgId, menuId, null);

      // Assert
      expect(mockCategoryRepository.findByMenuId).toHaveBeenCalledWith(
        orgId,
        menuId,
        null
      );
    });
  });

  describe('getById', () => {
    it('should return category when found', async () => {
      // Arrange
      const category = createMockCategory();
      mockCategoryRepository.findById.mockResolvedValue(category);

      // Act
      const result = await service.getById(orgId, 'cat_123');

      // Assert
      expect(result).toEqual(category);
    });

    it('should return null when category not found', async () => {
      // Arrange
      mockCategoryRepository.findById.mockResolvedValue(null);

      // Act
      const result = await service.getById(orgId, 'nonexistent');

      // Assert
      expect(result).toBeNull();
    });
  });

  describe('getByIdWithRelations', () => {
    it('should return category with relations when found', async () => {
      // Arrange
      const categoryWithRelations = createMockCategoryWithRelations();
      mockCategoryRepository.findByIdWithRelations.mockResolvedValue(
        categoryWithRelations
      );

      // Act
      const result = await service.getByIdWithRelations(orgId, 'cat_123');

      // Assert
      expect(result).toEqual(categoryWithRelations);
    });

    it('should throw AppException when category not found', async () => {
      // Arrange
      mockCategoryRepository.findByIdWithRelations.mockResolvedValue(null);

      // Act & Assert
      await expect(
        service.getByIdWithRelations(orgId, 'nonexistent')
      ).rejects.toThrow(AppException);
    });

    it('should include products when requested', async () => {
      // Arrange
      const categoryWithProducts = createMockCategoryWithRelations({
        products: [{ id: 'prod_1', name: 'Product 1' }] as any,
      });
      mockCategoryRepository.findByIdWithRelations.mockResolvedValue(
        categoryWithProducts
      );

      // Act
      await service.getByIdWithRelations(orgId, 'cat_123', true);

      // Assert
      expect(mockCategoryRepository.findByIdWithRelations).toHaveBeenCalledWith(
        'cat_123',
        orgId,
        true
      );
    });
  });

  // ---------------------------------------------------------------------------
  // Create Operations Tests
  // ---------------------------------------------------------------------------

  describe('create', () => {
    const validCreateData = {
      menuId,
      name: 'New Category',
      description: 'A new category',
    };

    it('should create a category successfully', async () => {
      // Arrange
      const createdCategory = createMockCategory({
        name: validCreateData.name,
        slug: 'new-category',
      });
      mockMenuRepository.findByIdOrThrow.mockResolvedValue(createMockMenu());
      mockCategoryRepository.slugExists.mockResolvedValue(false);
      mockCategoryRepository.create.mockResolvedValue(createdCategory);
      mockEventService.emitCustom.mockResolvedValue(undefined);

      // Act
      const result = await service.create(orgId, validCreateData);

      // Assert
      expect(result.category).toEqual(createdCategory);
      expect(result.message).toContain('successfully');
      expect(mockEventService.emitCustom).toHaveBeenCalledWith(
        'category.created',
        expect.objectContaining({
          categoryId: createdCategory.id,
          menuId,
          organizationId: orgId,
        })
      );
    });

    it('should verify menu exists before creating', async () => {
      // Arrange
      mockMenuRepository.findByIdOrThrow.mockRejectedValue(
        AppException.notFound('Menu', menuId)
      );

      // Act & Assert
      await expect(service.create(orgId, validCreateData)).rejects.toThrow(
        AppException
      );
      expect(mockCategoryRepository.create).not.toHaveBeenCalled();
    });

    it('should verify parent category exists when provided', async () => {
      // Arrange
      const dataWithParent = {
        ...validCreateData,
        parentId: 'parent_cat',
      };
      mockMenuRepository.findByIdOrThrow.mockResolvedValue(createMockMenu());
      mockCategoryRepository.findById.mockResolvedValue(null);

      // Act & Assert
      await expect(service.create(orgId, dataWithParent)).rejects.toThrow(
        AppException
      );
    });

    it('should throw error when parent is in different menu', async () => {
      // Arrange
      const dataWithParent = {
        ...validCreateData,
        parentId: 'parent_cat',
      };
      const parentInDifferentMenu = createMockCategory({
        id: 'parent_cat',
        menuId: 'different_menu',
      });
      mockMenuRepository.findByIdOrThrow.mockResolvedValue(createMockMenu());
      mockCategoryRepository.findById.mockResolvedValue(parentInDifferentMenu);

      // Act & Assert
      await expect(service.create(orgId, dataWithParent)).rejects.toThrow(
        AppException
      );
    });

    it('should generate unique slug when slug exists', async () => {
      // Arrange
      const createdCategory = createMockCategory({ slug: 'new-category-1' });
      mockMenuRepository.findByIdOrThrow.mockResolvedValue(createMockMenu());
      mockCategoryRepository.slugExists
        .mockResolvedValueOnce(true)
        .mockResolvedValueOnce(false);
      mockCategoryRepository.create.mockResolvedValue(createdCategory);
      mockEventService.emitCustom.mockResolvedValue(undefined);

      // Act
      await service.create(orgId, validCreateData);

      // Assert
      expect(mockCategoryRepository.create).toHaveBeenCalledWith(
        orgId,
        expect.objectContaining({ slug: 'new-category-1' })
      );
    });

    it('should throw error when provided slug already exists', async () => {
      // Arrange
      const dataWithSlug = {
        ...validCreateData,
        slug: 'existing-slug',
      };
      mockMenuRepository.findByIdOrThrow.mockResolvedValue(createMockMenu());
      mockCategoryRepository.slugExists.mockResolvedValue(true);

      // Act & Assert
      await expect(service.create(orgId, dataWithSlug)).rejects.toThrow(
        AppException
      );
    });
  });

  // ---------------------------------------------------------------------------
  // Update Operations Tests
  // ---------------------------------------------------------------------------

  describe('update', () => {
    const validUpdateData = {
      name: 'Updated Category',
      description: 'Updated description',
    };

    it('should update a category successfully', async () => {
      // Arrange
      const existingCategory = createMockCategory();
      const updatedCategory = createMockCategory({
        name: validUpdateData.name,
        description: validUpdateData.description,
      });
      mockCategoryRepository.findByIdOrThrow.mockResolvedValue(existingCategory);
      mockCategoryRepository.update.mockResolvedValue(updatedCategory);
      mockEventService.emitCustom.mockResolvedValue(undefined);

      // Act
      const result = await service.update(orgId, 'cat_123', validUpdateData);

      // Assert
      expect(result.category).toEqual(updatedCategory);
      expect(result.message).toContain('successfully');
      expect(mockEventService.emitCustom).toHaveBeenCalledWith(
        'category.updated',
        expect.objectContaining({
          categoryId: updatedCategory.id,
        })
      );
    });

    it('should throw error when category not found', async () => {
      // Arrange
      mockCategoryRepository.findByIdOrThrow.mockRejectedValue(
        AppException.notFound('Category', 'nonexistent')
      );

      // Act & Assert
      await expect(
        service.update(orgId, 'nonexistent', validUpdateData)
      ).rejects.toThrow(AppException);
    });

    it('should check slug uniqueness when changing slug', async () => {
      // Arrange
      const existingCategory = createMockCategory();
      mockCategoryRepository.findByIdOrThrow.mockResolvedValue(existingCategory);
      mockCategoryRepository.slugExists.mockResolvedValue(true);

      // Act & Assert
      await expect(
        service.update(orgId, 'cat_123', { slug: 'existing-slug' })
      ).rejects.toThrow(AppException);
    });

    it('should prevent circular reference when changing parent', async () => {
      // Arrange
      const existingCategory = createMockCategory();
      mockCategoryRepository.findByIdOrThrow.mockResolvedValue(existingCategory);

      // Act & Assert
      await expect(
        service.update(orgId, 'cat_123', { parentId: 'cat_123' })
      ).rejects.toThrow(AppException);
    });

    it('should verify new parent is in same menu', async () => {
      // Arrange
      const existingCategory = createMockCategory();
      const parentInDifferentMenu = createMockCategory({
        id: 'parent_cat',
        menuId: 'different_menu',
      });
      mockCategoryRepository.findByIdOrThrow.mockResolvedValue(existingCategory);
      mockCategoryRepository.findById.mockResolvedValue(parentInDifferentMenu);

      // Act & Assert
      await expect(
        service.update(orgId, 'cat_123', { parentId: 'parent_cat' })
      ).rejects.toThrow(AppException);
    });
  });

  // ---------------------------------------------------------------------------
  // Reorder Operations Tests
  // ---------------------------------------------------------------------------

  describe('reorder', () => {
    it('should reorder categories successfully', async () => {
      // Arrange
      const reorderItems = [
        { id: 'cat_1', sortOrder: 0 },
        { id: 'cat_2', sortOrder: 1 },
        { id: 'cat_3', sortOrder: 2 },
      ];
      mockMenuRepository.findByIdOrThrow.mockResolvedValue(createMockMenu());
      mockCategoryRepository.reorder.mockResolvedValue(undefined);
      mockEventService.emitCustom.mockResolvedValue(undefined);

      // Act
      const result = await service.reorder(orgId, {
        menuId,
        items: reorderItems,
      });

      // Assert
      expect(result.count).toBe(3);
      expect(result.message).toContain('successfully');
      expect(mockCategoryRepository.reorder).toHaveBeenCalledWith(
        orgId,
        menuId,
        reorderItems
      );
      expect(mockEventService.emitCustom).toHaveBeenCalledWith(
        'category.reordered',
        expect.objectContaining({
          menuId,
          items: reorderItems,
        })
      );
    });

    it('should verify menu exists before reordering', async () => {
      // Arrange
      mockMenuRepository.findByIdOrThrow.mockRejectedValue(
        AppException.notFound('Menu', menuId)
      );

      // Act & Assert
      await expect(
        service.reorder(orgId, { menuId, items: [] })
      ).rejects.toThrow(AppException);
    });
  });

  describe('moveToParent', () => {
    it('should move category to new parent', async () => {
      // Arrange
      const movedCategory = createMockCategory({ parentId: 'new_parent' });
      mockCategoryRepository.moveToParent.mockResolvedValue(movedCategory);
      mockEventService.emitCustom.mockResolvedValue(undefined);

      // Act
      const result = await service.moveToParent(orgId, 'cat_123', 'new_parent');

      // Assert
      expect(result.parentId).toBe('new_parent');
      expect(mockEventService.emitCustom).toHaveBeenCalledWith(
        'category.updated',
        expect.objectContaining({
          changes: { parentId: 'new_parent' },
        })
      );
    });

    it('should move category to root', async () => {
      // Arrange
      const movedCategory = createMockCategory({ parentId: null });
      mockCategoryRepository.moveToParent.mockResolvedValue(movedCategory);
      mockEventService.emitCustom.mockResolvedValue(undefined);

      // Act
      const result = await service.moveToParent(orgId, 'cat_123', null);

      // Assert
      expect(result.parentId).toBeNull();
    });
  });

  // ---------------------------------------------------------------------------
  // Active Status Tests
  // ---------------------------------------------------------------------------

  describe('toggleActive', () => {
    it('should toggle category from active to inactive', async () => {
      // Arrange
      const activeCategory = createMockCategory({ isActive: true });
      const inactiveCategory = createMockCategory({ isActive: false });
      mockCategoryRepository.findByIdOrThrow.mockResolvedValue(activeCategory);
      mockCategoryRepository.update.mockResolvedValue(inactiveCategory);
      mockEventService.emitCustom.mockResolvedValue(undefined);

      // Act
      const result = await service.toggleActive(orgId, 'cat_123');

      // Assert
      expect(result.isActive).toBe(false);
      expect(mockCategoryRepository.update).toHaveBeenCalledWith(
        'cat_123',
        orgId,
        { isActive: false }
      );
    });

    it('should toggle category from inactive to active', async () => {
      // Arrange
      const inactiveCategory = createMockCategory({ isActive: false });
      const activeCategory = createMockCategory({ isActive: true });
      mockCategoryRepository.findByIdOrThrow.mockResolvedValue(inactiveCategory);
      mockCategoryRepository.update.mockResolvedValue(activeCategory);
      mockEventService.emitCustom.mockResolvedValue(undefined);

      // Act
      const result = await service.toggleActive(orgId, 'cat_123');

      // Assert
      expect(result.isActive).toBe(true);
    });
  });

  // ---------------------------------------------------------------------------
  // Delete Operations Tests
  // ---------------------------------------------------------------------------

  describe('delete', () => {
    it('should soft delete a category successfully', async () => {
      // Arrange
      const categoryWithNoChildren = createMockCategoryWithRelations({
        children: [],
      });
      mockCategoryRepository.findByIdWithRelations.mockResolvedValue(
        categoryWithNoChildren
      );
      mockCategoryRepository.softDelete.mockResolvedValue(undefined);
      mockEventService.emitCustom.mockResolvedValue(undefined);

      // Act
      await service.delete(orgId, 'cat_123');

      // Assert
      expect(mockCategoryRepository.softDelete).toHaveBeenCalledWith('cat_123', orgId);
      expect(mockEventService.emitCustom).toHaveBeenCalledWith(
        'category.deleted',
        expect.objectContaining({
          categoryId: categoryWithNoChildren.id,
        })
      );
    });

    it('should throw error when category not found', async () => {
      // Arrange
      mockCategoryRepository.findByIdWithRelations.mockResolvedValue(null);

      // Act & Assert
      await expect(service.delete(orgId, 'nonexistent')).rejects.toThrow(
        AppException
      );
    });

    it('should throw error when category has children', async () => {
      // Arrange
      const categoryWithChildren = createMockCategoryWithRelations({
        children: [createMockCategory({ id: 'child_1' })] as any,
      });
      mockCategoryRepository.findByIdWithRelations.mockResolvedValue(
        categoryWithChildren
      );

      // Act & Assert
      await expect(service.delete(orgId, 'cat_123')).rejects.toThrow(
        AppException
      );
      expect(mockCategoryRepository.softDelete).not.toHaveBeenCalled();
    });
  });

  describe('restore', () => {
    it('should restore a soft-deleted category', async () => {
      // Arrange
      const restoredCategory = createMockCategory();
      mockCategoryRepository.restore.mockResolvedValue(restoredCategory);
      mockEventService.emitCustom.mockResolvedValue(undefined);

      // Act
      const result = await service.restore(orgId, 'cat_123');

      // Assert
      expect(result).toEqual(restoredCategory);
      expect(mockEventService.emitCustom).toHaveBeenCalledWith(
        'category.restored',
        expect.any(Object)
      );
    });
  });

  // ---------------------------------------------------------------------------
  // Validation Operations Tests
  // ---------------------------------------------------------------------------

  describe('isSlugAvailable', () => {
    it('should return true when slug is available', async () => {
      // Arrange
      mockCategoryRepository.slugExists.mockResolvedValue(false);

      // Act
      const result = await service.isSlugAvailable(orgId, menuId, 'available-slug');

      // Assert
      expect(result).toBe(true);
    });

    it('should return false when slug is taken', async () => {
      // Arrange
      mockCategoryRepository.slugExists.mockResolvedValue(true);

      // Act
      const result = await service.isSlugAvailable(orgId, menuId, 'taken-slug');

      // Assert
      expect(result).toBe(false);
    });

    it('should exclude current category when checking slug', async () => {
      // Arrange
      mockCategoryRepository.slugExists.mockResolvedValue(false);

      // Act
      await service.isSlugAvailable(orgId, menuId, 'current-slug', 'cat_123');

      // Assert
      expect(mockCategoryRepository.slugExists).toHaveBeenCalledWith(
        orgId,
        menuId,
        'current-slug',
        'cat_123'
      );
    });
  });

  describe('count', () => {
    it('should return category count for a menu', async () => {
      // Arrange
      mockCategoryRepository.count.mockResolvedValue(10);

      // Act
      const result = await service.count(orgId, menuId);

      // Assert
      expect(result).toBe(10);
    });

    it('should filter by active status', async () => {
      // Arrange
      mockCategoryRepository.count.mockResolvedValue(7);

      // Act
      await service.count(orgId, menuId, true);

      // Assert
      expect(mockCategoryRepository.count).toHaveBeenCalledWith(orgId, menuId, true);
    });
  });

  describe('countAll', () => {
    it('should return total category count for organization', async () => {
      // Arrange
      mockCategoryRepository.countAll.mockResolvedValue(25);

      // Act
      const result = await service.countAll(orgId);

      // Assert
      expect(result).toBe(25);
    });
  });
});
